import React, { useMemo } from "react";
import { useUploader } from "../MainUploader";
import { Button, Flex, Text } from "../../../_compat";
import { useLanguage } from "../../../_compat";

const SingleFileUploader = () => {
    const { onPick, files, removeFile, disabled, placeholder } = useUploader();
    const { t } = useLanguage();

    const currentFileName = useMemo(() => {
        if (files.length > 0) return files[0]?.shortName;
        return null;
    }, [files]);

    return (
        <Flex w={"full"} gap={8} flexDirection={"row"} alignItems={"center"}>
            <Button
                label={currentFileName ?? placeholder ?? t("chooseFile")}
                severity={"secondary"}
                outlined
                w={"85%"}
                onClick={onPick as any}
                disabled={disabled}
            />
            <Button
                icon="pi pi-times"
                size={"sm"}
                severity={"danger"}
                outlined
                onClick={(e) => {
                    e?.stopPropagation?.();
                    if (files.length) removeFile(0)();
                }}
                disabled={!currentFileName || disabled}
            />
        </Flex>
    );
};

export default SingleFileUploader;
